mapper.update:
UPDATE TB_GROUP_CODE
SET GROUP_NAME = #{groupName},
    USE_YN     = #{useYn},
    REMARK     = #{remark}
WHERE GROUP_CODE = #{groupCode}

UPDATE TB_COMMON_CODE
SET CODE_NAME  = #{codeName},
    SORT_ORDER = #{sortOrder},
    USE_YN     = #{useYn},
    REMARK     = #{remark}
WHERE GROUP_CODE = #{groupCode}
  AND CODE_VALUE = #{codeValue}

mapper.delete:
DELETE FROM TB_COMMON_CODE
WHERE GROUP_CODE = #{groupCode}
  AND CODE_VALUE = #{codeValue}
